    }
}

class TradeExecution {
    func executeTrade(stockSymbol: String, quantity: Int, isBuying: Bool, completion: @escaping (Bool) -> Void) {
        let endpoint = "https://api.yourtradingplatform.com/trade"
        let parameters = ["symbol": stockSymbol, "quantity": quantity, "type": isBuying ? "buy" : "sell"]
        
        ApiManager.shared.secureRequest(endpoint, method: "POST", parameters: parameters) { data, error in
            if error == nil, let data = data {
                // Assuming a successful trade results in a 200 status
                let success = (try? JSONDecoder().decode(TradeResponse.self, from: data)) != nil
                completion(success)
            } else {
                completion(false)
            }
        }
    }
}

struct TradeResponse: Decodable {
    let success: Bool
}

class PortfolioManager {
    private var portfolio: [String: Int] = [:]

    func updatePortfolio(stockSymbol: String, quantity: Int, isAdding: Bool) {
        if isAdding {
            portfolio[stockSymbol, default: 0] += quantity
        } else {
            portfolio[stockSymbol, default: 0] -= quantity
            if portfolio[stockSymbol]! <= 0 {
                portfolio.removeValue(forKey: stockSymbol)
            }
        }
    }

    func getPortfolio() -> [String: Int] {
        return portfolio
    }
}

class TradingViewController: UIViewController {
    let tradeExecution = TradeExecution()
    let portfolioManager = PortfolioManager()

    func onBuyStock(stockSymbol: String, quantity: Int) {
        tradeExecution.executeTrade(stockSymbol: stockSymbol, quantity: quantity, isBuying: true) { [weak self] success in
            if success {
                self?.portfolioManager.updatePortfolio(stockSymbol: stockSymbol, quantity: quantity, isAdding: true)
                print("Transaction Successful: Bought \(quantity) shares of \(stockSymbol)")
            } else {
                print("Transaction Failed")
            }
        }
    }

    func onSellStock(stockSymbol: String, quantity: Int) {
        tradeExecution.executeTrade(stockSymbol: stockSymbol, quantity: quantity, isBuying: false) { [weak self] success in
            if success {
                self?.portfolioManager.updatePortfolio(stockSymbol: stockSymbol, quantity: quantity, isAdding: false)
                print("Transaction Successful: Sold \(quantity) shares of \(stockSymbol)")
            } else {
                print("Transaction Failed")
            }
        }
    }
}